import React, { useState } from 'react';

const gold = '#D4AF37';
const terracotta = '#C04000';
const clayLight = '#E2725B';

const Menu = () => {
  const [showCustomModal, setShowCustomModal] = useState(false);

  const regularChops = [
    { name: "The Executive Box", price: "15,000", desc: "Samosa, Mosa, Chicken & Puff Puff." },
    { name: "Mini Munch", price: "5,500", desc: "10 mixed pieces for one." }
  ];

  return (
    <div style={{ padding: '0 20px', marginTop: '-20px' }}>
      
      {/* 1. THE HERO CARD (200k Item) */}
      <div style={{ 
        width: '100%', 
        borderRadius: '15px', 
        overflow: 'hidden', 
        marginBottom: '25px',
        background: `linear-gradient(135deg, ${terracotta} 0%, #222 100%)`, // Luxury Gradient
        border: `1px solid ${gold}44`
      }}>
        <div style={{ padding: '25px' }}>
          <span style={{ 
            fontSize: '0.6rem', color: gold, border: `1px solid ${gold}`, 
            padding: '2px 8px', borderRadius: '4px', textTransform: 'uppercase', fontWeight: 'bold' 
          }}>Bespoke Curation</span>
          
          <h2 style={{ fontSize: '1.3rem', color: '#fff', margin: '10px 0 5px 0', letterSpacing: '1px' }}>
            THE ÀMÍ SIGNATURE GRAND PLATTER
          </h2>
          
          <p style={{ fontSize: '0.75rem', color: '#ccc', margin: '0 0 20px 0', lineHeight: '1.6' }}>
            Handcrafted for your finest guests of 60 and above. A bespoke curation designed for elite gatherings.
          </p>
          
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
              <span style={{ fontSize: '0.6rem', color: gold, display: 'block' }}>INVESTMENT STARTS AT</span>
              <span style={{ fontSize: '1.2rem', fontWeight: 'bold', color: '#fff' }}>₦200,000</span>
            </div>
            <button 
              onClick={() => setShowCustomModal(true)}
              style={{ 
                backgroundColor: '#fff', color: '#000', border: 'none', 
                padding: '12px 20px', borderRadius: '8px', fontWeight: 'bold', fontSize: '0.75rem' 
              }}>
              CUSTOMIZE
            </button>
          </div>
        </div>
      </div>

      {/* 2. REGULAR ITEMS */}
      <h3 style={{ fontSize: '0.7rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '15px' }}>
        Daily Platters
      </h3>
      {regularChops.map((item) => (
        <div key={item.name} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', marginBottom: '10px', padding: '12px', alignItems: 'center' }}>
          <div style={{ width: '55px', height: '55px', backgroundColor: '#000', borderRadius: '8px', marginRight: '15px' }}></div>
          <div style={{ flex: 1 }}>
            <h4 style={{ fontSize: '0.85rem', margin: '0', color: '#fff' }}>{item.name}</h4>
            <div style={{ fontSize: '0.9rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
          </div>
          <button style={{ backgroundColor: '#222', color: '#fff', border: 'none', borderRadius: '20px', padding: '6px 14px', fontSize: '0.65rem' }}>ADD</button>
        </div>
      ))}

      {/* 3. THE SLIDE-UP CUSTOMIZATION PANEL */}
      {showCustomModal && (
        <div style={{ 
          position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', 
          backgroundColor: 'rgba(0,0,0,0.9)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' 
        }}>
          <div style={{ 
            width: '100%', backgroundColor: '#161616', borderTopLeftRadius: '25px', borderTopRightRadius: '25px', 
            padding: '30px 25px', boxSizing: 'border-box'
          }}>
            <div style={{ width: '40px', height: '4px', backgroundColor: '#333', borderRadius: '2px', margin: '0 auto 20px' }}></div>
            <h2 style={{ color: gold, fontSize: '1.2rem', marginBottom: '5px' }}>Tailor Your Platter</h2>
            <p style={{ color: '#888', fontSize: '0.75rem', marginBottom: '20px' }}>Our team will contact you to finalize the details for your 60+ guests.</p>
            
            <textarea 
              placeholder="Tell us about your event (Date, location, and flavor preferences)..." 
              style={{ width: '100%', height: '120px', backgroundColor: '#000', border: '1px solid #333', borderRadius: '10px', color: '#fff', padding: '15px', marginBottom: '20px', fontSize: '0.85rem' }}
            />
            
            <button 
              onClick={() => setShowCustomModal(false)}
              style={{ width: '100%', padding: '16px', backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '10px', fontWeight: 'bold' }}>
              REQUEST QUOTE
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Menu;
